SET NAMES utf8mb4;
UPDATE articles SET content_blocks = '[{"type": "subheading", "color": "text-fuchsia-300", "label": "Supplemental Material", "small": true}, {"type": "heading", "label": "1. Video Example of Close Microphone Capture of the Bandoneon\'s Dynamic Stereo Field"}, {"url": "https://player.vimeo.com/video/1188180014?badge=0&autopause=0&player_id=0&app_id=58479", "type": "video"}, {"text": "Close microphone placement preserves the bandoneon\'s dynamic stereo field, as sound from each side of the instrument continuously changes with bellows movement.", "type": "text", "small": true}, {"type": "heading", "label": "2. Example of Selected Sound Bank Sounds"}, {"url": "https://res.cloudinary.com/djxcomnwb/video/upload/v1740569103/extended-bandoneon/soundbank/mp3/uf0ldgemfjelhjrijwhf.mp3", "type": "sound", "label": "Air Vibrato"}, {"url": "https://res.cloudinary.com/djxcomnwb/video/upload/v1740660384/extended-bandoneon/soundbank/mp3/ccl96y9ce9j4hhuoygwb.mp3", "type": "sound", "label": "Cluster Right Hand"}, {"url": "https://www.extendedbandoneon.com/soundbank", "type": "link", "label": "Larger sound bank available at:"}, {"type": "heading", "label": "3. Video and Audio examples of a Recording Session for Peripheral and Discarded Sounds"}, {"text": "This video documents a recording session focused on peripheral and discarded sounds of the bandoneon: wood sounds, bellows, tapping on materials, mechanical sounds of the interior, pitched-air sounds and incidental bodily noises.\\nThe footage is accelerated, and the sounds are intentionally subtle, almost imperceptible. The audio file shows curated sound samples from the same recording session, taken through the DPA 4099 Core microphones.", "type": "text"}, {"url": "https://player.vimeo.com/video/1187188364", "type": "video"}, {"url": "https://res.cloudinary.com/djxcomnwb/video/upload/v1777536970/soundbank/mp3/rsbcbddofge0xdapjfl7.mp3", "type": "sound", "label": "Recording Session Curated Sounds"}, {"url": "https://www.extendedbandoneon.com/soundbank", "type": "link", "label": "Larger sound bank available at:"}, {"type": "heading", "label": "4. Observed differences in how bandoneon sounds elicit stable and consistent responses\\nduring training and interaction."}, {"rows": [["Air Sounds - Long", "Medium", "Variable"], ["Air Sound - Short", "High", "Consistent"], ["Air Sound - Vibrato", "Medium", "Variable"], ["Bellows Sounds - Percussive - Bellow Shake with Air Sound", "Medium", "Unstable"], ["Single Button Sound", "High", "Consistent"], ["Buttons Sounds - Textural", "High", "Consistent"], ["Tapping on wood casing with fingertips", "High", "Variable"], ["Tapping on wood casing with fingernails", "High", "Variable"], ["Friction of bellows and clothes - e.g. bellows and trousers", "Medium", "Variable"], ["High Pitched Notes - Long", "Medium", "Inconsistent"], ["High Pitched Notes - Short", "Medium", "Variable"], ["Medium Pitched Notes - Long and Short", "Medium", "Inconsistent"], ["Medium Pitched Notes - Long and Short", "Low", "Inconsistent"], ["Clusters - Singled and Doubled Handed", "Low", "Inconsistent"]], "type": "table", "headers": ["Sound Type", "Recognisability (System)", "System Response"]}, {"type": "heading", "label": "5. Neons & Neutrals Documentation"}, {"type": "subheading", "label": "About"}, {"text": "Neons & Neutrals is a solo performance for bandoneon and live electronics that explores the instrument\'s transformation through extended techniques, movement, and technology. The work engages with the bandoneon as an augmented instrument within a multichannel environment, examining how traditional instruments evolve through electronic interaction.", "type": "text"}, {"type": "subheading", "label": "Neons & Neutrals \u2013 Practice Session (Bandoneon & Live Electronics) - Video\u00a0Documentation", "centered": true}, {"text": "Place: Black Box, Helsinki Music Centre, Sibelius Academy, Finland\\nDate: 18.3.2025", "type": "text", "centered": true}, {"url": "https://www.youtube.com/embed/qh4tQXV7MMI", "type": "video"}, {"type": "subheading", "label": "Neons & Neutrals \u2013 Performance Excerpts (Bandoneon & Live Electronics) - Video\u00a0Documentation", "centered": true, "spaceBefore": true}, {"text": "Place: Black Box, Helsinki Music Centre, Sibelius Academy, Finland\\nDate: 18.3.2025", "type": "text", "centered": true}, {"url": "https://www.youtube.com/embed/54pOZawlfiw", "type": "video"}, {"type": "heading", "label": "6. Scratched Surfaces Documentation"}, {"type": "subheading", "label": "About"}, {"text": "Scratched Surfaces is a performative sound installation that explores the subtle sonic elements of the bandoneon. These sounds are diffused across an eight-channel system, eight speaker cones, and two guitar amplifiers, accompanied by a video projection on a tablet featuring footage drawn from the artist\'s practice. The work forms part of the doctoral research project Bandoneon Resonances.", "type": "text"}, {"type": "subheading", "label": "Scratched Surfaces - Performative Intervention During Sound Installation - Video\\nDocumentation", "centered": true}, {"text": "Place: Black Box, Helsinki Music Centre, Sibelius Academy, Finland\\nDate: 24.11.2025", "type": "text", "centered": true}, {"url": "https://www.youtube.com/embed/aacsZoYssg0", "type": "video"}, {"url": "https://mekrapov.com/scratched-surfaces", "type": "link", "label": "More about Scratched Surfaces available at:"}]' WHERE id = 2;